code = """# Let's check what storage variables we have available
import json

# Read the UNIV CALIFORNIA patents from the file
with open('/tmp/tmpe4y1e6k8.json', 'r') as f:
    uc_patents = json.load(f)

print(f"Total UNIV CALIFORNIA patents: {len(uc_patents)}")
print("\nFirst patent sample:")
print(json.dumps(uc_patents[0], indent=2)[:1000])

# Extract all citations from UC patents
all_citations = []
for patent in uc_patents:
    citation_str = patent.get('citation', '[]')
    if citation_str and citation_str != '[]':
        try:
            citations = json.loads(citation_str)
            for cit in citations:
                pub_num = cit.get('publication_number')
                if pub_num:
                    all_citations.append(pub_num)
        except:
            pass

print(f"\nTotal citation references: {len(all_citations)}")
print(f"Unique cited patents: {len(set(all_citations))}")
print("Sample cited patents:", list(set(all_citations))[:10])"""

